import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { authApi } from '../../api/client';
import { useAuth } from '../../context/AuthContext';

export default function LoginPage() {
  const [step, setStep]     = useState('phone'); // 'phone' | 'otp'
  const [phone, setPhone]   = useState('');
  const [otp, setOtp]       = useState('');
  const [loading, setLoading] = useState(false);
  const { login }           = useAuth();
  const navigate            = useNavigate();

  const handleSendOtp = async (e) => {
    e.preventDefault();
    const formatted = phone.startsWith('+') ? phone : '+998' + phone;
    setLoading(true);
    try {
      await authApi.sendOtp(formatted);
      setPhone(formatted);
      setStep('otp');
      toast.success('SMS yuborildi!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xato yuz berdi');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { data } = await authApi.verifyOtp(phone, otp);
      login(data.data);
      toast.success(data.message);

      const role = data.data.role;
      if (role === 'ADMIN')   navigate('/admin');
      else if (role === 'COURIER') navigate('/courier');
      else navigate('/');
    } catch (err) {
      toast.error(err.response?.data?.message || 'OTP noto\'g\'ri');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <div style={styles.logo}>Xorazm<span style={styles.logoAccent}>Delivery</span></div>
        <p style={styles.subtitle}>Xorazm bo'ylab tez yetkazib berish</p>

        {step === 'phone' ? (
          <form onSubmit={handleSendOtp}>
            <label style={styles.label}>Telefon raqam</label>
            <div style={styles.phoneRow}>
              <span style={styles.prefix}>+998</span>
              <input
                style={styles.input}
                type="tel"
                placeholder="90 123 45 67"
                value={phone.replace('+998', '')}
                onChange={(e) => setPhone(e.target.value.replace(/\D/g, '').slice(0, 9))}
                maxLength={9}
                required
              />
            </div>
            <button style={styles.btn} type="submit" disabled={loading}>
              {loading ? 'Yuborilmoqda...' : 'SMS kod olish'}
            </button>
          </form>
        ) : (
          <form onSubmit={handleVerifyOtp}>
            <p style={styles.phoneConfirm}>{phone} ga SMS yuborildi</p>
            <label style={styles.label}>6 xonali kod</label>
            <input
              style={{ ...styles.input, textAlign: 'center', fontSize: 24, letterSpacing: 8 }}
              type="text"
              placeholder="000000"
              value={otp}
              onChange={(e) => setOtp(e.target.value.replace(/\D/g, '').slice(0, 6))}
              maxLength={6}
              autoFocus
              required
            />
            <button style={styles.btn} type="submit" disabled={loading || otp.length < 6}>
              {loading ? 'Tekshirilmoqda...' : 'Kirish'}
            </button>
            <button
              style={styles.btnLink}
              type="button"
              onClick={() => { setStep('phone'); setOtp(''); }}
            >
              ← Raqamni o'zgartirish
            </button>
          </form>
        )}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    background: '#F7F9F8',
  },
  card: {
    background: '#fff',
    borderRadius: 20,
    padding: '40px 36px',
    width: 360,
    boxShadow: '0 2px 24px rgba(0,0,0,0.08)',
  },
  logo: {
    fontFamily: 'Syne, sans-serif',
    fontWeight: 800,
    fontSize: 28,
    color: '#0D7A6A',
    textAlign: 'center',
    marginBottom: 4,
  },
  logoAccent: { color: '#EF9F27' },
  subtitle: { textAlign: 'center', color: '#6b8080', fontSize: 14, marginBottom: 28 },
  label: { display: 'block', fontSize: 13, fontWeight: 500, color: '#6b8080', marginBottom: 6 },
  phoneRow: { display: 'flex', alignItems: 'center', gap: 8 },
  prefix: {
    padding: '10px 12px',
    background: '#F0F5F4',
    borderRadius: 9,
    fontSize: 14,
    fontWeight: 500,
    color: '#0D7A6A',
    border: '1px solid rgba(13,122,106,0.15)',
  },
  input: {
    width: '100%',
    padding: '10px 14px',
    border: '1px solid rgba(13,122,106,0.2)',
    borderRadius: 9,
    fontSize: 16,
    outline: 'none',
    boxSizing: 'border-box',
  },
  btn: {
    width: '100%',
    marginTop: 16,
    padding: '13px 0',
    background: '#0D7A6A',
    color: '#fff',
    border: 'none',
    borderRadius: 10,
    fontSize: 15,
    fontWeight: 600,
    cursor: 'pointer',
  },
  btnLink: {
    width: '100%',
    marginTop: 10,
    padding: '8px 0',
    background: 'transparent',
    border: 'none',
    color: '#6b8080',
    fontSize: 13,
    cursor: 'pointer',
    textDecoration: 'underline',
  },
  phoneConfirm: { fontSize: 13, color: '#0D7A6A', marginBottom: 16, fontWeight: 500 },
};
